{
  "idea": "Soil-Prithvi: A field-scale geospatial foundation model fusing Prithvi-EO-2.0, spectroscopy, and in-situ sensors for carbon-enabled soil digital twins.",
  "idea_description": "This idea extends Prithvi-EO-2.0 and spatiotemporal ML by integrating above-ground satellite imagery with below-ground soil spectroscopy and in-situ sensor networks to build a unified field-scale soil digital twin. The model will track SOC change while incorporating subsurface soil properties, carbon stocks, and dynamics that satellite imagery alone cannot measure. It combines geospatial foundations with soil-specific, subsurface data, enabling more accurate, interpretable, and actionable monitoring of carbon dynamics across agricultural fields. The resulting digital twin can support precision agriculture, carbon credit validation, and climate change mitigation strategies.",
  "technical_plan": {
    "target_problem": "Field-scale SOC change monitoring requires above-ground satellite remote sensing plus below-ground soil spectroscopy and sensor data to track carbon dynamics.",
    "core_method": "Train a spatiotemporal foundation model that fuses Prithvi-EO-2.0 satellite imagery, soil spectroscopy data, and in-situ sensor measurements to predict SOC status, change, and carbon dynamics at the field scale.",
    "limitation_addressed": "Satellite imagery alone lacks subsurface soil information needed for soil-specific SOC monitoring and carbon dynamics tracking.",
    "expected_result": "A field-scale soil digital twin that accurately tracks SOC change by integrating above-ground remote sensing with below-ground spectroscopy and sensor networks."
  },
  "lineage_connection": {
    "source_ideas": [
      "Prithvi-EO-2.0: A powerful general-purpose geospatial foundation",
      "Spatiotemporal ML enables SOC change monitoring"
    ],
    "reused_parts": [
      "Prithvi-EO-2.0 geospatial foundation",
      "Spatiotemporal ML for SOC change monitoring"
    ],
    "changed_parts": [
      "Add fusion with below-ground soil spectroscopy and sensor networks",
      "Build a unified soil digital twin for carbon dynamics tracking"
    ],
    "why_next_step": "Because SOC monitoring needs above-ground satellite sensing combined with subsurface soil data, this extends Prithvi-EO-2.0 and spatiotemporal ML toward soil-specific carbon-enabled digital twins.",
    "lineage_risk": "If subsurface soil data are not widely available or interoperable with satellite imagery, the proposed fusion may lack sufficient training data or ground-truth validation."
  },
  "evaluation_plan": {
    "setup": "Test the model on a field-scale dataset combining Prithvi-EO-2.0 satellite imagery, soil spectroscopy measurements, and in-situ SOC sensor networks across multiple agricultural fields.",
    "baselines": [
      "Satellite-only SOC monitoring",
      "Spectroscopy-only SOC estimation",
      "In-situ sensor-only SOC tracking"
    ],
    "metrics": [
      "Mean absolute error in SOC prediction",
      "Accuracy of SOC change detection",
      "Model interpretability and subsurface signal attribution",
      "Transferability across field types and seasons"
    ],
    "risks": [
      "Limited availability or alignment of subsurface soil data with satellite imagery",
      "Temporal mismatch between satellite acquisitions and sensor/spectroscopy measurements",
      "Overfitting to field-specific conditions without generalizable soil digital twin behavior"
    ]
  }
}
